  lhs <- .to_latex_prec(x@args[[1L]], names_map)
  rhs <- .to_latex_prec(x@args[[2L]], names_map)
  list(
    latex = paste0(lhs$latex, " = ", rhs$latex),
    prec = .LATEX_PREC$COMPARE
  )
}

