  ## args: [X, t]
  X_ltx <- .to_latex_prec(x@args[[1L]], names_map)
  t_ltx <- .to_latex_prec(x@args[[2L]], names_map)
  list(
    latex = paste0("\\cvxnorm{", X_ltx$latex, "}_2 \\leq ", t_ltx$latex),
    prec = .LATEX_PREC$COMPARE
  )
}

